1	#pragma once
2	
3	#include <cute/tensor.hpp>
4	#include <kerutils/kerutils.cuh>
5	
6	namespace sm100 {
7	
8	/*
9	Load K/V indices from global memory, and generate validity mask
10	Each thread loads 8 indices
11	Should be called by lanes 0 ~ (BLOCK_TOPK/8)
12	*/
13	CUTE_DEVICE
14	char load_indices_and_generate_mask(
15	    int lane_idx,
16	    int* gIndices,
17	    int s_kv,
18	    int abs_pos_start,
19	    int topk_length
20	) {
21	    int indices[8];
22	    KU_LDG_256(
23	        gIndices + lane_idx*8, 
24	        indices,
25	        ".nc", 
26	        "no_allocate", 
27	        "evict_normal", 
28	        "256B"
29	    );
30	    auto is_valid = [&](int rel_pos_in_lane, int index) -> char {
31	        int abs_pos = abs_pos_start + lane_idx*8 + rel_pos_in_lane;
32	        return index >= 0 && index < s_kv && abs_pos < topk_length;
33	    };
34	    char is_ks_valid_mask = \
35	        is_valid(7, indices[7]) << 7 | 
36	        is_valid(6, indices[6]) << 6 | 
37	        is_valid(5, indices[5]) << 5 |
38	        is_valid(4, indices[4]) << 4 |
39	        is_valid(3, indices[3]) << 3 |
40	        is_valid(2, indices[2]) << 2 |
41	        is_valid(1, indices[1]) << 1 |
42	        is_valid(0, indices[0]) << 0;
43	    return is_ks_valid_mask;
44	}
45	
46	
47	/*
48	Get P from Tensor Memory, reduce P within shared memory, perform masking, and store back if necessary
49	
50	Initially, since dual gemm is used, we have two P pieces in Tensor Memory, one occupying rows 0 ~ 63 while the other occupying rows 64 ~ 127. We'd like to have them reduced into one single P piece, stored in registers with layout:
51	
52	        N       N    ---   (topk)
53	    +-------+-------+
54	    |       |       |
55	32  | Warp0 | Warp2 |
56	    |       |       |
57	    +-------+-------+
58	    |       |       |
59	32  | Warp1 | Warp3 |
60	    |       |       |
61	    +-------+-------+
62	|
63	(head)
64	
65	where N = NUM_ELEMS_PER_THREAD
66	*/
67	template<
68	    int NUM_ELEMS_PER_THREAD,
69	    int TMEM_COL_START,
70	    int BARRIER_WARP02_SYNC_ID,
71	    int BARRIER_WARP13_SYNC_ID,
72	    bool STORE_BACK_P
73	>
74	CUTE_DEVICE
75	void retrieve_mask_and_reduce_p(
76	    char* k_validness_base,
77	    int local_warp_idx,
78	    int lane_idx,
79	    auto slot_bar_P_empty_arrival,
80	    float p_exchange_buf[4][32*NUM_ELEMS_PER_THREAD],
81	    float p[NUM_ELEMS_PER_THREAD]
82	) {
83	    using namespace cute;
84	    using cutlass::arch::NamedBarrier;
85	    static_assert(BARRIER_WARP13_SYNC_ID == BARRIER_WARP02_SYNC_ID+1);
86	
87	    float p_peer[NUM_ELEMS_PER_THREAD];
88	    if (local_warp_idx < 2) {
89	        ku::tmem_ld_32dp32bNx<NUM_ELEMS_PER_THREAD>(TMEM_COL_START, p);
90	        ku::tmem_ld_32dp32bNx<NUM_ELEMS_PER_THREAD>(TMEM_COL_START + NUM_ELEMS_PER_THREAD, p_peer);
91	    } else {
92	        ku::tmem_ld_32dp32bNx<NUM_ELEMS_PER_THREAD>(TMEM_COL_START, p_peer);
93	        ku::tmem_ld_32dp32bNx<NUM_ELEMS_PER_THREAD>(TMEM_COL_START + NUM_ELEMS_PER_THREAD, p);
94	    }
95	    cutlass::arch::fence_view_async_tmem_load();
96	    ku::tcgen05_before_thread_sync();
97	    slot_bar_P_empty_arrival();
98	
99	    // Mask invalid tokens
100	    // We put masking before reduction, since (-inf) + anything (except nan and +inf) is (-inf), which guarantees correctness, and this can overlap with smem load
101	    static_assert(NUM_ELEMS_PER_THREAD == 32);
102	    uint32_t is_k_valid = *(uint32_t*)(k_validness_base + (local_warp_idx>=2?NUM_ELEMS_PER_THREAD/8:0));
103	    CUTE_UNROLL
104	    for (int i = 0; i < NUM_ELEMS_PER_THREAD; i += 1) {
105	        if (!(is_k_valid >> i & 1))
106	            p[i] = -CUDART_INF_F;
107	    }
108	
109	    // Reduce P within the cluster
110	    {
111	        // Store
112	        // Warp 0, 1 store their right (col 32 ~ 63) part, while warp 2, 3 store their left (row 0 ~ 31) part
113	        CUTE_UNROLL
114	        for (int i = 0; i < NUM_ELEMS_PER_THREAD/4; ++i) {
115	            ku::st_shared(&p_exchange_buf[local_warp_idx^2][i*32*4 + lane_idx*4], *(float4*)(p_peer + i*4));
116	        }
117	        NamedBarrier::arrive_and_wait(64, BARRIER_WARP02_SYNC_ID + (local_warp_idx&1));
118	        CUTE_UNROLL
119	        for (int i = 0; i < NUM_ELEMS_PER_THREAD/4; ++i) {
120	            float2 t[2];
121	            *(float4*)t = *(float4*)(&p_exchange_buf[local_warp_idx][i*32*4 + lane_idx*4]);
122	            float2* cur_p = (float2*)(p + i*4);
123	            cur_p[0] = ku::float2_add(cur_p[0], t[0]);
124	            cur_p[1] = ku::float2_add(cur_p[1], t[1]);
125	        }
126	    }
127	
128	    if constexpr (STORE_BACK_P) {
129	        CUTE_UNROLL
130	        for (int i = 0; i < NUM_ELEMS_PER_THREAD/4; ++i) {
131	            ku::st_shared(&p_exchange_buf[local_warp_idx][i*32*4 + lane_idx*4], *(float4*)(p+i*4));
132	        }
133	    }
134	}
135	
136	/*
137	Rescale O in Tensor Memory.
138	
139	O should occupy 128 rows x (D_V/2) columns in Tensor Memory.
140	*/
141	template<
142	    int D_V,
143	    int CHUNK_SIZE,
144	    int TMEM_COL_START
145	>
146	CUTE_DEVICE
147	void rescale_O(
148	    float scale_factor
149	) {
150	    float2 scale_factor_float2 = {scale_factor, scale_factor};
151	    float2 o[CHUNK_SIZE/2];
152	
153	    CUTE_UNROLL
154	    for (int chunk_idx = 0; chunk_idx < (D_V/2)/CHUNK_SIZE; ++chunk_idx) {
155	        // Load O
156	        ku::tmem_ld_32dp32bNx<CHUNK_SIZE>(TMEM_COL_START + chunk_idx*CHUNK_SIZE, o);
157	        cutlass::arch::fence_view_async_tmem_load();
158	
159	        // Mult
160	        for (int i = 0; i < CHUNK_SIZE/2; ++i) {
161	            o[i] = ku::float2_mul(o[i], scale_factor_float2);
162	        }
163	
164	        // Store O
165	        ku::tmem_st_32dp32bNx<CHUNK_SIZE>(TMEM_COL_START + chunk_idx*CHUNK_SIZE, o);
166	        cutlass::arch::fence_view_async_tmem_store();
167	    }
168	}
169	
170	template<int NUM_ELEMS_PER_THREAD>
171	CUTE_DEVICE
172	float get_max(
173	    float p[NUM_ELEMS_PER_THREAD]
174	) {
175	    float local_max = -CUDART_INF_F;
176	    CUTE_UNROLL
177	    for (int i = 0; i < NUM_ELEMS_PER_THREAD; ++i) {
178	        local_max = max(local_max, p[i]);
179	    }
180	    return local_max;
181	}
182	
183	/*
184	Calculate s := exp2f(p*scale - new_max) and its sum
185	*/
186	template<int NUM_ELEMS_PER_THREAD>
187	CUTE_DEVICE
188	float get_s_from_p(
189	    nv_bfloat162 s[NUM_ELEMS_PER_THREAD/2],
190	    float p[NUM_ELEMS_PER_THREAD],
191	    float scale,
192	    float new_max
193	) {
194	    float2 cur_sum = float2 {0.0f, 0.0f};
195	    float2 neg_new_max_float2 = float2 {-new_max, -new_max};
196	    float2 scale_float2 = float2 {scale, scale};
197	    CUTE_UNROLL
198	    for (int i = 0; i < NUM_ELEMS_PER_THREAD/2; i += 1) {
199	        float2 d = ku::float2_fma(float2{p[i*2], p[i*2+1]}, scale_float2, neg_new_max_float2);
200	        d.x = exp2f(d.x);
201	        d.y = exp2f(d.y);
202	        cur_sum = ku::float2_add(cur_sum, d);
203	        s[i] = __float22bfloat162_rn(d);
204	    }
205	    return cur_sum.x + cur_sum.y;
206	}
207	
208	}
