313	                // Load O from tO
314	                if (have_valid_indices) {
315	                    ku::tmem_ld_32dp32bNx<B_EPI>(tmem_cols::O + c*128 + k*B_EPI, o);
316	                    cutlass::arch::fence_view_async_tmem_load();
317	                }
318	
319	                // Convert and store
320	                CUTE_UNROLL
321	                for (int i = 0; i < B_EPI/8; ++i) {
322	                    nv_bfloat162 o_bf16[4];
323	                    CUTE_UNROLL
324	                    for (int j = 0; j < 4; ++j) {
325	                        o[i*4+j] = ku::float2_mul(o[i*4+j], output_scale_float2);
326	                        o_bf16[j] = __float22bfloat162_rn(o[i*4+j]);
327	                    }
328	                    *(uint128_t*)(sO_addrs[i] + (c*(D_V/2) + (idx_in_warpgroup/64)*(D_V/4) + k*B_EPI)*64) = *(uint128_t*)(o_bf16);
329	                }
330	
331	                // Sync
332	                fence_view_async_shared();
333	                NamedBarrier::arrive_and_wait(128, NamedBarriers::wg0_sync);
334	                
335	                if (warp_idx == 0 && elect_one_sync()) {
336	                    int epi_chunk_idx = c*(D_V/2/B_EPI) + k;
337	                    cute::copy(
338	                        tma_params.tma_O,
339	                        thr_tma.partition_S(sO_divided(_, _, epi_chunk_idx)),
340	                        thr_tma.partition_D(tma_gO(_, _, epi_chunk_idx))
341	                    );
342	                }
343	                if (warp_idx == 1 && elect_one_sync()) {
344	                    int epi_chunk_idx = c*(D_V/2/B_EPI) + (D_V/B_EPI/4) + k;
345	                    cute::copy(
346	                        tma_params.tma_O,
347	                        thr_tma.partition_S(sO_divided(_, _, epi_chunk_idx)),
348	                        thr_tma.partition_D(tma_gO(_, _, epi_chunk_idx))
349	                    );
350	                }
351	            }
352	        }
353	
354	
355	        if (warp_idx == 0) {
356	            cute::TMEM::Allocator1Sm().free(0, 512);
357	        }
358	    } else if (warpgroup_idx == 1) {
359	        // Producer warp for KV
360	        int warp_idx = cutlass::canonical_warp_idx_sync() - 4;
361	        constexpr int NUM_WARPS = 4, NUM_LOCAL_ROWS_PER_WARP = (B_TOPK/4)/NUM_WARPS;
362	        if (elect_one_sync()) {
363	            CUTE_NO_UNROLL
364	            for (int k = 0; k < num_k_blocks; ++k) {
365	                int4 indices[NUM_LOCAL_ROWS_PER_WARP];
366	                int max_indices = -1, min_indices = params.s_kv;
367	                CUTE_UNROLL
368	                for (int local_row = 0; local_row < NUM_LOCAL_ROWS_PER_WARP; ++local_row) {
369	                    indices[local_row] = __ldg((int4*)(gIndices + k*B_TOPK) + local_row*NUM_WARPS + warp_idx);
370	                    max_indices = max(max_indices, int4_max(indices[local_row]));
371	                    min_indices = min(min_indices, int4_min(indices[local_row]));
372	                }
373	                bool is_all_rows_invalid = min_indices == params.s_kv || max_indices == -1;
374	                bool should_skip_tma = is_all_rows_invalid && k >= NUM_BUFS;
375	
376	                if (k == 2) {
377	                    plan.bar_prologue_utccp_nope.wait(0);   // Since q_nope coincidences with k[2]
378	                }
379	
380	                // Copy NoPE
381	                int cur_buf = k%NUM_BUFS;
382	                plan.bar_sv_done[cur_buf].wait((k/NUM_BUFS)&1^1);
383	                bf16* sK_nope_base = plan.u.k.k_nope[cur_buf].data() + warp_idx*4*64;
384	
385	                auto load_kv_nope_part = [&](int part_idx) {
386	                    CUTE_UNROLL
387	                    for (int local_row = 0; local_row < NUM_LOCAL_ROWS_PER_WARP; ++local_row) {
388	                        CUTE_UNROLL
389	                        for (int local_col = part_idx*(D_V/2/64); local_col < (part_idx+1)*(D_V/2/64); ++local_col) {
390	                            ku::tma_gather4(
391	                                &(tma_params.tensor_map_kv_nope),
392	                                plan.bar_kv_nope_ready[cur_buf][part_idx],
393	                                sK_nope_base + local_row*(4*NUM_WARPS)*64 + local_col*(B_TOPK*64),
394	                                local_col*64,
395	                                indices[local_row],
396	                                (int64_t)TMA::CacheHintSm90::EVICT_LAST
397	                            );
398	                        }
399	                    }
400	                };
401	
402	                if (!should_skip_tma) {
403	                    load_kv_nope_part(0);
404	                    load_kv_nope_part(1);
405	                } else {
406	                    // NOTE See head128/phase1.cuh for this TMA skipping technique
407	                    CUTE_UNROLL
408	                    for (int part_idx = 0; part_idx < 2; ++part_idx)
409	                        plan.bar_kv_nope_ready[cur_buf][part_idx].complete_transaction(NUM_LOCAL_ROWS_PER_WARP*4*D_V/2*sizeof(bf16));
410	                }
411	            }
412	        }
413	    } else {
414	        // MMA warp
415	        if (warp_idx == 8 && elect_one_sync()) {
416	            // S -> T copy for Q
417	            UMMA::SmemDescriptor sQ_nope_desc = UMMA::make_umma_desc<UMMA::Major::K>(
418	                make_tensor(
419	                    make_smem_ptr(plan.u.q_full.q_nope.data()),
420	                    tile_to_shape(
421	                        UMMA::Layout_K_SW128_Atom<bf16>{},
422	                        Shape<Int<B_H*2>, Int<64>>{}    // We use this shape for dual gemm (TODO Link)
423	                    )
424	                )
425	            );
426	            UMMA::SmemDescriptor sQ_rope_desc = UMMA::make_umma_desc<UMMA::Major::K>(
427	                make_tensor(
428	                    make_smem_ptr(plan.s_q_rope.q_rope.data()),
429	                    tile_to_shape(
430	                        UMMA::Layout_K_SW64_Atom<bf16>{},
431	                        Shape<Int<B_H*2>, Int<32>>{}
432	                    )
433	                )
434	            );
435	            
436	            if constexpr (HAVE_ROPE) {
437	                // Copy the RoPE tile: 128 rows * 32 cols (64B) (in UTCCP's view), or 64 rows * 64 cols (in our view)
438	                plan.bar_prologue_q_rope.arrive_and_expect_tx(B_H*(D_Q-D_V)*sizeof(bf16));
439	                plan.bar_prologue_q_rope.wait(0);
440	                ku::tcgen05_after_thread_sync();
441	                CUTE_UNROLL
442	                for (int subtile_idx = 0; subtile_idx < 2; ++subtile_idx) {
443	                    // A subtile is 128 rows * 16 cols (256b, 32B) (in UTCCP's view), or 64 rows * 16 cols * 2 (in our view)
444	                    SM100_UTCCP_128dp256bit_1cta::copy(
445	                        sQ_rope_desc + (subtile_idx*32) / 16,
446	                        tmem_cols::Q_RoPE + subtile_idx*8
447	                    );
448	                }
449	                ku::umma_arrive_noelect(plan.bar_prologue_utccp_rope);
450	            }
451	
452	            plan.bar_prologue_q_nope.arrive_and_expect_tx(B_H*D_V*sizeof(bf16));
453	            plan.bar_prologue_q_nope.wait(0);
454	            ku::tcgen05_after_thread_sync();
455	            CUTE_UNROLL
456	            for (int tile_idx = 0; tile_idx < D_V/64/2; ++tile_idx) {
457	                // A tile is 128 rows * 64 cols (128B) (in UTCCP's view), or 64 rows * 128 cols (in our view)
458	                CUTE_UNROLL
459	                for (int subtile_idx = 0; subtile_idx < 4; ++subtile_idx) {
460	                    // A subtile is 128 rows * 16 cols (256b, 32B) (in UTCCP's view), or 64 rows * 16 cols * 2 (in our view)
461	                    SM100_UTCCP_128dp256bit_1cta::copy(
462	                        sQ_nope_desc + (tile_idx*(B_H*128*2) + subtile_idx*32) / 16,   // Remember that 4 LSBs are not included
463	                        tmem_cols::Q + tile_idx*32 + subtile_idx*8
464	                    );
465	                }
466	            }
467	            ku::umma_arrive_noelect(plan.bar_prologue_utccp_nope);
468	
469	            if constexpr (HAVE_ROPE) {
470	                plan.bar_prologue_utccp_rope.wait(0);
471	            }
472	
473	            CUTE_NO_UNROLL
474	            for (int k = 0; k < num_k_blocks+1; ++k) {
475	                if (k < num_k_blocks) {
476	                    // Pi = QKi^T
477	                    int cur_buf = k%NUM_BUFS;
478	                    Tensor sK_nope = make_tensor(make_smem_ptr(plan.u.k.k_nope[cur_buf].data()), SmemLayoutKNoPE_TiledMMA{});
479	                    Tensor sK_rope = make_tensor(make_smem_ptr(plan.u.k.k_rope.data()), SmemLayoutKRoPE_TiledMMA{});
480	
481	                    plan.bar_p_free.wait(k&1^1);
482	                    ku::tcgen05_after_thread_sync();
483	                    
484	                    // Wait for K (RoPE)
485	                    // P = Q(rope) @ K(rope)^T
486	                    if constexpr (HAVE_ROPE) {
487	                        plan.bar_kv_rope_ready.wait(k&1);
488	                        ku::tcgen05_after_thread_sync();
489	                        ku::utcmma_ts(tiled_mma_P, tQ_rope, sK_rope, tP, true);
490	                        ku::umma_arrive_noelect(plan.bar_qk_rope_done);
491	                    }
492	
493	                    // Wait for K (NoPE)
494	                    if (k == 0) {
495	                        plan.bar_prologue_utccp_nope.wait(0);
496	                    }
497	                    Tensor sK_nope_divided = flat_divide(sK_nope, Tile<Int<B_TOPK*2>, Int<D_V/4>>{})(_, _, _0{}, _);
498	                    CUTE_UNROLL
499	                    for (int kv_nope_part_idx = 0; kv_nope_part_idx < 2; ++kv_nope_part_idx) {
500	                        plan.bar_kv_nope_ready[cur_buf][kv_nope_part_idx].arrive_and_expect_tx(B_TOPK*D_V/2*sizeof(bf16));
501	                        plan.bar_kv_nope_ready[cur_buf][kv_nope_part_idx].wait((k/NUM_BUFS)&1);
502	                        ku::tcgen05_after_thread_sync();
503	
504	                        // P += Q(nope) @ K(nope)^T
505	                        bool clear_accum = (!HAVE_ROPE) && kv_nope_part_idx == 0;
506	                        ku::utcmma_ts(tiled_mma_P, kv_nope_part_idx ? tQ_nope_part1 : tQ_nope_part0, sK_nope_divided(_, _, kv_nope_part_idx), tP, clear_accum);
507	                    }
508	                    ku::umma_arrive_noelect(plan.bar_qk_nope_done[cur_buf]);
509	                }
510	                if (k > 0) {
511	                    // O += S(i-1)V(i-1)
512	                    int cur_buf = (k-1)%NUM_BUFS;
513	
514	                    Tensor sS = make_tensor(make_smem_ptr(plan.s_q_rope.s), SmemLayoutS{});
515	                    Tensor sV = make_tensor(make_smem_ptr(plan.u.k.k_nope[cur_buf].data()), SmemLayoutV{});
516	
517	                    // Wait for S(i-1) and O to be scaled
518	                    plan.bar_so_ready.wait((k-1)&1);
519	                    ku::tcgen05_after_thread_sync();
520	
521	                    // O += sS @ sV
522	                    ku::utcmma_ss(tiled_mma_O, sS, sV, tO, k == 1);
523	                    ku::umma_arrive_noelect(plan.bar_sv_done[cur_buf]);
524	                }
525	            }
526	        } else if (warp_idx == 9) {
527	            // KV valid loading warp
528	            if (lane_idx < B_TOPK/8) {
529	                CUTE_NO_UNROLL
530	                for (int k = 0; k < num_k_blocks; ++k) {
531	                    char k_validness_mask = load_indices_and_generate_mask(
532	                        lane_idx,
533	                        gIndices + k*B_TOPK,
534	                        params.s_kv,
535	                        k*B_TOPK,
536	                        topk_length
537	                    );
538	
539	                    int cur_buf = k%NUM_BUFS;
540	                    plan.bar_k_valid_free[cur_buf].wait((k/NUM_BUFS)&1^1);
541	                    plan.is_k_valid[cur_buf][lane_idx] = k_validness_mask;
542	                    plan.bar_k_valid_ready[cur_buf].arrive();
543	                }
544	            }
545	        } else if (warp_idx == 10 || warp_idx == 11) {
546	            if constexpr (HAVE_ROPE) {
547	                int thread_idx = threadIdx.x - 10*32;
548	                constexpr int GROUP_SIZE = 8, NUM_GROUPS = 64/GROUP_SIZE, ROWS_PER_THREAD = B_TOPK/NUM_GROUPS;
549	                int group_idx = thread_idx / GROUP_SIZE, idx_in_group = thread_idx % GROUP_SIZE;
550	                Tensor sK_rope = make_tensor(make_smem_ptr(plan.u.k.k_rope.data()), SmemLayoutKRoPE{});
551	                bf16* sK_rope_base = &sK_rope(group_idx, idx_in_group*8);
552	                CUTE_NO_UNROLL
553	                for (int k = 0; k < num_k_blocks; ++k) {
554	                    int indices[ROWS_PER_THREAD];
555	                    CUTE_UNROLL
556	                    for (int local_row = 0; local_row < ROWS_PER_THREAD; ++local_row)
557	                        indices[local_row] = __ldg(gIndices + k*B_TOPK + group_idx + local_row*NUM_GROUPS);
558	                    plan.bar_qk_rope_done.wait(k&1^1);
559	                    CUTE_UNROLL
560	                    for (int local_row = 0; local_row < ROWS_PER_THREAD; ++local_row) {
561	                        int index = indices[local_row];
562	                        ku::cp_async_cacheglobal<ku::PrefetchSize::B128>(
563	                            params.kv + (int64_t)index*params.stride_kv_s_kv + 512 + idx_in_group*8,
564	                            sK_rope_base + local_row*NUM_GROUPS*32,
565	                            index >= 0 && index < params.s_kv
566	                        );  // NOTE Using cp.async instead of TMA is faster here
567	                        // NOTE Here we only consider the range of `index` instead of also checking against topk_length, as it's noted that under this scenario (i.e. there exists a valid index among indices[topk_length: ] that points to a token who has NaN inside)
568	                    }
569	                    cutlass::arch::cpasync_barrier_arrive_noinc((uint64_t*)&(plan.bar_kv_rope_ready));
570	                }
571	            }
572	        }
573	    }
574	
575	
576	#else
577	    if (cute::thread0()) {
578	        CUTE_INVALID_CONTROL_PATH("This kernel only supports sm100");
579	    }
580	#endif
581	}
582	
583	template<int D_QK>
584	void run_fwd_phase1_kernel(const SparseAttnFwdParams& params) {
585	    KU_ASSERT(params.h_kv == 1);
586	    KU_ASSERT(params.topk % B_TOPK == 0);   // To save some boundry checkings
587	    KU_ASSERT(params.h_q == B_H);  // To save some calculation
588	    KU_ASSERT(params.d_qk == D_QK);
589	    static_assert(D_QK == 576 || D_QK == 512);
590	
591	    auto shape_Q_nope = make_shape(params.h_q, D_V, params.s_q);
592	    auto tma_Q_nope = cute::make_tma_copy(
593	        SM90_TMA_LOAD{},
594	        make_tensor(
595	            make_gmem_ptr((bf16*)params.q),
596	            make_layout(
597	                shape_Q_nope,
598	                make_stride(params.stride_q_h_q, _1{}, params.stride_q_s_q)
599	            )
600	        ),
601	        SmemLayoutQNoPE{}
602	    );
603	
604	    auto shape_Q_rope = make_shape(params.h_q, D_Q-D_V, params.s_q);
605	    auto tma_Q_rope = cute::make_tma_copy(
606	        SM90_TMA_LOAD{},
607	        make_tensor(
608	            make_gmem_ptr((bf16*)params.q + D_V),
609	            make_layout(
610	                shape_Q_rope,
611	                make_stride(params.stride_q_h_q, _1{}, params.stride_q_s_q)
612	            )
613	        ),
614	        SmemLayoutQRoPE{}
615	    );
616	
617	    auto shape_O = make_shape(params.h_q, params.d_v, params.s_q);
618	    auto tma_O = cute::make_tma_copy(
619	        SM90_TMA_STORE{},
620	        make_tensor(
621	            make_gmem_ptr((bf16*)params.out),
622	            make_layout(
623	                shape_O,
624	                make_stride(params.d_v, _1{}, params.h_q*params.d_v)
625	            )
626	        ),
627	        SmemLayoutOTiles<1>{}
628	    );
629	
630	
631	    CUtensorMap tensor_map_kv_nope;
632	    {
633	        uint64_t size[2] = {D_V, (unsigned long)params.s_kv};
634	        uint64_t stride[1] = {params.stride_kv_s_kv*sizeof(bf16)};
635	        uint32_t box_size[2] = {64, 1};
636	        uint32_t elem_stride[2] = {1, 1};
637	        CUresult res = CUTLASS_CUDA_DRIVER_WRAPPER_CALL(cuTensorMapEncodeTiled)(
638	            &tensor_map_kv_nope,
639	            CUtensorMapDataType::CU_TENSOR_MAP_DATA_TYPE_BFLOAT16,
640	            2,
641	            params.kv,
642	            size,
643	            stride,
644	            box_size,
645	            elem_stride,
646	            CUtensorMapInterleave::CU_TENSOR_MAP_INTERLEAVE_NONE,
647	            CUtensorMapSwizzle::CU_TENSOR_MAP_SWIZZLE_128B,
648	            CUtensorMapL2promotion::CU_TENSOR_MAP_L2_PROMOTION_L2_256B,
649	            CUtensorMapFloatOOBfill::CU_TENSOR_MAP_FLOAT_OOB_FILL_NONE
650	        );
651	        KU_ASSERT(res == CUresult::CUDA_SUCCESS);
652	    }
653	
654	    TmaParams<
655	        decltype(shape_Q_nope), decltype(tma_Q_nope),
656	        decltype(shape_Q_rope), decltype(tma_Q_rope),
657	        decltype(shape_O), decltype(tma_O)
658	    > tma_params = {
659	        shape_Q_nope, tma_Q_nope,
660	        shape_Q_rope, tma_Q_rope,
661	        shape_O, tma_O,
662	        tensor_map_kv_nope
663	    };
664	    auto kernel = &sparse_attn_fwd_kernel<D_QK == 576, decltype(tma_params)>;
665	
666	    constexpr size_t smem_size = sizeof(SharedMemoryPlan);
667	    KU_CUDA_CHECK(cudaFuncSetAttribute(kernel, cudaFuncAttributeMaxDynamicSharedMemorySize, smem_size));
668	
669	    kernel<<<params.s_q, NUM_THREADS, smem_size, params.stream>>>(params, tma_params);
670	    KU_CHECK_KERNEL_LAUNCH();
671	}
672	
673	}
