55	static constexpr int B_TOPK = 64; // For 2 CTAs
56	static constexpr int NUM_THREADS = 128*4;
57	static constexpr int NUM_WORKER_THREADS = IS_PREFILL ? (128 + 4 + (B_TOPK/8) + 1 + 128)*2 + 1 : (128 + 128 + 1 + 32 + 2 + 128)*2;
58	
59	// For non-decode mode, we have 4 (half-)KV buffers
60	// For decode mode, we have 3 (half-)KV buffers with two raw KV buffers
61	static constexpr int NUM_K_BUFS = IS_DECODE ? 3 : 4;
62	static constexpr int NUM_RAW_K_BUFS = IS_DECODE ? 2 : 0;
63	static constexpr int NUM_INDEX_BUFS = IS_DECODE ? 4 : 4;
64	
65	static constexpr int D_NOPE = 448;
66	static constexpr int D_ROPE = 64;
67	static constexpr int TMA_K_STRIDE_FOR_DECODING = D_NOPE + 2*D_ROPE;
68	static constexpr int NUM_SCALES_EACH_TOKEN = 8; // 7 scales + 1 padding
69	
70	static constexpr int B_EPI = 64;                // Epilogue block size for normal case (i.e. prefill or non-splitkv decoding)
71	static constexpr int B_EPI_SPLITKV = 32;        // Epilogue block size for splitkv decoding
72	static constexpr int NUM_EPI_SPLITKV_BUFS = 4;  // The number of epilogue buffers for splitkv decoding
73	static_assert((H_Q/2)*D_Q*sizeof(bf16) >= NUM_EPI_SPLITKV_BUFS*(H_Q/2)*(B_EPI_SPLITKV*2)*sizeof(float));
74	
75	// Tensor memory columns
76	struct tmem_cols {
77	    //   0 ~ 256: Output accumulator
78	    // 256 ~ 384: Q
79	    // 384 ~ 448: P
80	    static constexpr int O = 0;
81	    static constexpr int Q = 256;
82	    static constexpr int P = 384;
83	};
84	
85	struct SharedMemoryPlan {
86	    array_aligned<bf16, (H_Q/2)*D_Q> Q; // Will be output for epilogue
87	    array_aligned<bf16, B_TOPK*(D_K/2)> K[NUM_K_BUFS];
88	    array_aligned<fp8_e4m3, B_TOPK*(D_K/2)> K_raw[NUM_RAW_K_BUFS];
89	    array_aligned<bf16, (H_Q/2)*B_TOPK> S;
90	    float P_exchange[4][(H_Q/2/2)*(B_TOPK/2)];
91	    float rowwise_max_buf[128], rowwise_li_buf[128];
92	
93	    CUTE_ALIGNAS(16) char is_k_valid[NUM_INDEX_BUFS][B_TOPK/8];
94	    CUTE_ALIGNAS(16) int tma_coord[NUM_INDEX_BUFS][B_TOPK];
95	    CUTE_ALIGNAS(16) fp8_e8m0 scales[NUM_INDEX_BUFS][B_TOPK][NUM_SCALES_EACH_TOKEN/2];
96	    
97	    transac_bar_t bar_sQ_full, bar_tQ_empty, bar_tQ_full;
98	    transac_bar_t bar_tOut_full, bar_tOut_empty;
99	    transac_bar_t bar_KV_full[NUM_K_BUFS], bar_KV_empty[NUM_K_BUFS];
100	    transac_bar_t bar_P_empty;
101	    transac_bar_t bar_QK_done, bar_SV_done;
102	    transac_bar_t bar_S_O_full;
103	    transac_bar_t bar_li_full, bar_li_empty;
104	
105	    // The following barriers are prefill-only
106	    transac_bar_t bar_clc_full, bar_clc_empty;
107	
108	    // The following barriers are decode-only
109	    transac_bar_t bar_raw_KV_full[NUM_RAW_K_BUFS], bar_raw_KV_empty[NUM_RAW_K_BUFS];
110	    transac_bar_t bar_valid_coord_scales_full[NUM_INDEX_BUFS], bar_valid_coord_scales_empty[NUM_INDEX_BUFS];
111	
112	    ku::CLCResponseObj clc_response_obj;
113	    array_aligned<uint32_t, 1> tmem_start_addr;
114	};
115	
116	using TiledMMA_P = decltype(make_tiled_mma(
117	    SM100_MMA_F16BF16_2x1SM_TS_NOELECT<bf16, bf16, float, H_Q, B_TOPK*2, UMMA::Major::K, UMMA::Major::K>{}
118	)); // *2 for dual gemm
119	
120	using TiledMMA_O = decltype(make_tiled_mma(
121	    SM100_MMA_F16BF16_2x1SM_SS_NOELECT<bf16, bf16, float, H_Q, 256, UMMA::Major::K, UMMA::Major::MN>{},
122	    Layout<Shape<_1, _1, _1>>{},
123	    Tile<Int<128>, Layout<Shape<_128, _2, _2>, Stride<_1, _256, _128>>, _16>{}  // We use this permutation layout to let CTA0 takes V[:, 0:256] and CTA1 takes V[:, 256:512]
124	));
