130	    cute::cluster_sync();   // We must add a cluster_sync() here, or TMA from CTA1 may launch before barrier initialization in CTA0
131	
132	    if (warp_idx == 0) {
133	        if (elect_one_sync()) {
134	            // Copy Q
135	            Tensor gQ = flat_divide(
136	                tma_params.tma_Q.get_tma_tensor(tma_params.shape_Q)(_, _, s_q_idx),
137	                Tile<Int<B_H/2>>{}
138	            )(_, cta_idx, _);
139	            ku::launch_tma_copy(tma_params.tma_Q, gQ, sQ_full, plan.bar_prologue_q, TMA::CacheHintSm90::EVICT_FIRST);
140	        }
141	
142	        // Initialize TMEM
143	        cute::TMEM::Allocator2Sm().allocate(512, plan.tmem_start_addr.data());
144	        TRAP_ONLY_DEVICE_ASSERT(plan.tmem_start_addr.data()[0] == 0);
145	        cute::TMEM::Allocator2Sm().release_allocation_lock();
146	    }
147	
148	    __syncthreads();    // Wait for TMEM allocation
149	
150	    if (warpgroup_idx == 0) {
151	        cutlass::arch::warpgroup_reg_alloc<144>();
152	        // Scale & Exp warps
153	
154	        // The following three numbers are 
155	        // - mi: max_logits used to scale Pi (i.e. O := exp2(Pi*scale - mi) @ V)
156	        // - li: sumexp, i.e. li := sum(exp(Pi*scale - mi))
157	        // - real_mi: real max logits, i.e. real_mi := max(Pi*scale)
158	        // where Pi is the i-th row of P, P := QK^T
159	        // mi and real_mi are always consistent within the two threads that
160	        // controls one row (i.e. thread 0+64, 1+65, 2+66, ...) after every update
161	        float mi = MAX_INIT_VAL;
162	        float li = 0.0f;
163	        float real_mi = -CUDART_INF_F;
164	
165	        const float2 scale = float2 {params.sm_scale_div_log2, params.sm_scale_div_log2};
166	        uint128_t* sS_base = (uint128_t*)plan.s.data() + idx_in_warpgroup%64 + 64*((idx_in_warpgroup/64)*8);
167	        float* sP_base = plan.p + idx_in_warpgroup%64*4 + (idx_in_warpgroup/64)*((B_H/2)*(B_TOPK/2));
168	
169	        CUTE_NO_UNROLL
170	        for (int k = 0; k < num_k_blocks; ++k) {
171	            // Wait for P
172	            plan.bar_qk_done[k%NUM_BUFS].wait((k/NUM_BUFS)&1);
173	            ku::tcgen05_after_thread_sync();
174	
175	            // Load P
176	            float2 p[(B_TOPK/2)/2];
177	            ku::tmem_ld_32dp32bNx<B_TOPK/2>(tmem_cols::p, p);
178	            cutlass::arch::fence_view_async_tmem_load();
179	            ku::tcgen05_before_thread_sync();
180	            plan.bar_p_free[k%NUM_BUFS].arrive(0u);
181	
182	            // Mask
183	            plan.bar_k_valid_ready[k%NUM_BUFS].wait((k/NUM_BUFS)&1);
184	            // The following code enables NVCC to use R2P instruction
185	            // Although we perform 2x LDS.32 instructions here, don't worry, NVCC will
186	            // convert them to one LDS.64 instruction. However, if we write LDS.64
187	            // here, NVCC won't use R2P.
188	            uint32_t is_k_valid_lo = *(uint32_t*)(plan.is_k_valid[k%NUM_BUFS] + (idx_in_warpgroup>=64?B_TOPK/8/2:0));
189	            uint32_t is_k_valid_hi = *(uint32_t*)(plan.is_k_valid[k%NUM_BUFS] + (idx_in_warpgroup>=64?B_TOPK/8/2:0) + 4);
190	            float* p_float = (float*)p;
191	            CUTE_UNROLL
192	            for (int i = 0; i < (B_TOPK/2)/2; i += 1) {
193	                if (!(is_k_valid_lo >> i & 1))
194	                    p_float[i] = -CUDART_INF_F;
195	            }
196	            CUTE_UNROLL
197	            for (int i = 0; i < (B_TOPK/2)/2; i += 1) {
198	                if (!(is_k_valid_hi >> i & 1))
199	                    p_float[i+(B_TOPK/2)/2] = -CUDART_INF_F;
200	            }
201	
202	            // Get rowwise max of Pi
203	            float cur_pi_max = -CUDART_INF_F;
204	            CUTE_UNROLL
205	            for (int i = 0; i < (B_TOPK/2); i += 1) {
206	                cur_pi_max = max(cur_pi_max, p_float[i]);
207	            }
208	            cur_pi_max *= params.sm_scale_div_log2;
209	
210	            plan.bar_k_valid_free[k%NUM_BUFS].arrive();
211	
212	            NamedBarrier::arrive_and_wait(128, 0);  // Wait for rowwise_max_buf and sP to be ready
