        float cur_lse = logf(li) + mi*CUDART_LN2_F;
        cur_lse = cur_lse == -CUDART_INF_F ? +CUDART_INF_F : cur_lse;
        params.max_logits[global_index] = real_mi*CUDART_LN2_F;
        params.lse[global_index] = cur_lse;
    }

